import{_ as a,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F14_負債結構與償債壓力測試_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F14_負債結構與償債壓力測試_投資研究員.md"}'),o={name:"審計報告庫/財務審計/8064_東捷/20260429/F14_負債結構與償債壓力測試_投資研究員.md"};function e(n,t,s,$,_,g){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="f14-負債結構與償債壓力測試-投資研究員-審計報告" tabindex="-1">F14: 負債結構與償債壓力測試 - 投資研究員 審計報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-投資研究員-審計報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 - 投資研究員 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li>負債比 38.14% ICR 31.04x 淨現金 $1.88B。高息防禦力極強，還款壓力為零，財務韌性超越同業均值。</li><li><strong>風險</strong>：低（S 級評等，結構穩健，利率抵禦深度充足） | <strong>時效</strong>：截至 2025 年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>診斷評級：S（優）</strong> — 淨現金部位巨額、利息保障倍數高於15、利率抵禦力極強</li><li><strong>負債比率</strong>：2023 年 48% → 2024 年 43% → 2025 年 <strong>38%</strong>（降10ppts，去槓桿明確）</li><li><strong>利息覆蓋倍數</strong>：2023 年 6x → 2024 年 15x → 2025 年 <strong>31x</strong></li><li><strong>淨債務/EBITDA</strong>：<strong>純淨現金</strong>，現金$2.42B遠高於總債務$540.9M</li><li><strong>短期債務佔比</strong>：短債$143.5M佔總借款52%，現金覆蓋16.8倍，再融資壓力零</li></ul><p><strong>診斷見解</strong>：短債佔比過半但現金覆蓋16.8倍，再融資風險為零。ICR 31x與負債比38%顯示去槓桿與獲利復甦雙動能確立。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1️⃣ 負債比與ICR</strong>：負債比三連降 48→43→38%，ICR 6→15→31x 三級跳改善。EBIT $347M 創新高，營業利益 $277M 為純本業貢獻，非業外一次項目，增長動能真實。ICR 31x 的意義是：即使營利腰斬，ICR 仍維持 15x 安全線以上，利率抵禦深度充足。</p><p><strong>2️⃣ 債務到期</strong>：短債 $143.5M 佔借貸 52% 名義集中度高，但現金 $2,419M 覆蓋短債 16.8 倍，再融資壓力實為零。長租 $254.7M 為 IFRS 16 強制資本化，對應廠房使用權非違約風險。未動用額度 $3,088M 構成備援流動性支撐。</p><p><strong>3️⃣ 百點利率測試</strong>：+100bps 僅增息 $2.8M，EPS 稀釋 $0.011（0.8%），衝擊微不足道。極端情境 EBIT 退回 $213M（2024 水準）+200bps，ICR 仍 12.8x，遠高於市場 5x 安全閥值。淨現金結構使東捷完全免疫於升息週期。</p><p><strong>4️⃣ 流動性缺口</strong>：現金 $2,419M 對比短債 $167M，溢餘 $2,252M（13.5 倍），短期支付極度寬裕。未動用額度 $3,088M 為備援安全墊，即使營運現金流歸零，流動性仍可支撐逾 12 個月。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><ul><li><strong>空頭風險一：營收依賴客戶集中度</strong>。東捷主要客戶群集中於面板與半導體設備業（友達集團關係）。若面板景氣再次如 2023-2024 年低迷，營業利益可能重挫導致 ICR 再降至 15x 以下，儘管仍在安全區，但將削弱市場估值溢價。</li><li><strong>空頭風險二：租賃負債長期鎖定</strong>。$266.14M 租賃負債中，&gt;$5 年部分佔 $254.65M，其中 20 年以上租約佔 $131.14M。若營運模式需要遷廠或縮編，長租合約將形成一次性違約金或減損風險。</li><li><strong>空頭風險三：現金收益被通膨侵蝕</strong>。帳上 $2.42B 現金若僅配置於低息存款（2025 年利息收入應低於借款利率），實質購買力每年被通膨稀釋約 2%，年隱含損失約 $48M（約 EPS $0.29），高於其借款利息支出。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源（Veracity Check） <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源（Veracity Check）&quot;">​</a></h2><ul><li><strong>2025 合併年報</strong>： <ul><li>資產負債表：總資產 $5,609,255K，總負債 $2,139,226K，負債比 38.14%</li><li>短期借款 $126,000K（利率 1.81%）。長期借款 $131,250K（利率 2.09%）。</li><li>現金及約當現金 $2,419,242K</li><li>利息費用總額 $11,179K（銀行借款 $5,807K + 租賃 $5,344K + 其他 $28K）</li><li>營業淨利 $276,824K，稅前淨利 $335,792K</li><li>EBIT: $335,792K + $11,179K = $346,971K</li><li>ICR: $346,971K / $11,179K = 31.04x</li><li>到期梯次表（p.61）：&lt;1 年 $146,933K、1-5 年 $78,104K、&gt;5 年 $63,541K</li><li>未動用額度（p.62）：無擔保 $2,184,153K、有擔保 $904,295K</li><li>流通在外股數：164,818K 股，EPS 1.36 元</li></ul></li><li><strong>2024 合併年報</strong>： <ul><li>負債比 42.86%，ICR 15.17x（用 EBIT 法）</li><li>若僅用營業利益/利息：$30,863K / $14,071K = 2.19x（當年非營業收益貢獻顯著）</li></ul></li><li><strong>跨表校準</strong>：負債總額($2,139.23M) = 流動負債($1,028.8M) + 非流動負債($1,110.4M)，與「負債及權益總計」勾稽一致。利息費用($11.18M) = 借款利息($5.81M) + 租賃利息($5.34M) + 其他($0.03M)，與財務成本明細勾稽一致。</li></ul>',18)])])}const d=a(o,[["render",e]]);export{h as __pageData,d as default};
